import{_ as a,o as t,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"76. Sabbatical Leave","description":"","frontmatter":{"title":"76. Sabbatical Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","sabbatical-leave","wages"]},"headers":[],"relativePath":"ebas/mspp/leave/76-sabbatical-leave.md","filePath":"ebas/mspp/leave/76-sabbatical-leave.md"}'),n={name:"ebas/mspp/leave/76-sabbatical-leave.md"};function s(l,e,r,p,c,b){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_76-sabbatical-leave" tabindex="-1">76. Sabbatical Leave <a class="header-anchor" href="#_76-sabbatical-leave" aria-label="Permalink to &quot;76. Sabbatical Leave&quot;">​</a></h1><p><strong>76.1</strong> Sabbatical Leave</p><p><strong>a.</strong> Sabbatical Leave is only available by mutual agreement between the Employee and the Employer.</p><p><strong>b.</strong> Subject to the provisions set out in clause 76.3 of this Agreement, Sabbatical Leave is only available for an Employee who is classified at Grade 3 level or higher, after the completion of a period of six years&#39; continuous service, as defined in clause 9aa.</p><p><strong>76.2</strong> Definitions For the purpose of this clause only, the following definitions apply:</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>a.</strong> Salary or Wage means the Employee’s salary or wage (including allowances) at the time leave is taken;</p><p><strong>b.</strong> Sabbatical Leave means up to a maximum of 26 weeks&#39; leave with pay.</p><p><strong>76.3</strong> Entitlement Where there is mutual agreement, Sabbatical Leave is taken on the following terms:</p><p><strong>a.</strong> An Employee who has been in the service of the same Health Service for the period specified in clause 76.1b of this Agreement shall be granted up to a maximum of 26 weeks&#39; leave of absence on full salary or wages.</p><p><strong>b.</strong> An Employee who meets the eligibility requirements in clause 76.1a and 76.1b above, shall be granted up to a maximum of 26 weeks’ leave of absence on full salary or wages.</p><p><strong>c.</strong> Sabbatical Leave may be taken in two periods of up to 13 weeks&#39; duration which are taken within 2 years of each other.</p><p><strong>d.</strong> The onus of proving a sufficient aggregate of service to support a claim for Sabbatical Leave will rest with the Employee.</p><p><strong>e.</strong> The Sabbatical Leave where agreed will be given as soon as practicable having regard to the needs of the Health Service, but the taking of such leave may be postponed to a mutually agreed date.</p><p><strong>f.</strong> The Employee’s application for sabbatical leave must be in writing and contain adequate details of the proposed programme of study or research.</p><p><strong>g.</strong> Subject to clause 76.3c, where an Employee proceeds on Sabbatical Leave of less than 26 weeks&#39; duration, the Employee will be deemed to have received their full entitlement under this clause and they will not be entitled to claim an entitlement representing (in part or in whole) the balance of the 26 weeks (if any). The absence of the Employee on Sabbatical Leave will be prima facie evidence that they have received their full entitlement under this clause. Where Sabbatical Leave is taken in two periods of 13 weeks as allowed under clause 76.3c, the provisions of this paragraph will apply to each 13 week period.</p><p><strong>h.</strong> Where an Employee has been granted Sabbatical Leave they may not reapply for Sabbatical Leave until a subsequent qualifying period as specified in clause 76.1b of this Agreement, which will not commence to run until the date of the Employee’s return to duty following Sabbatical Leave; provided that where by mutual agreement the Employee has delayed the taking of Sabbatical Leave, that period of service between the end of the qualifying period and the taking of such leave will be included as part of a subsequent qualifying period.</p><p>Plain language terms: sabbatical.</p>',18)])])}const g=a(n,[["render",s]]);export{d as __pageData,g as default};
